func TestHook_WiredIntoPersistentPreRun(t *testing.T) {
	t.Setenv("HOME", t.TempDir())
	t.Setenv(autoRefreshEnvVar, "")
	spy := &hookSpy{}
	spy.install(t)

	rc := RootCmd()
	rc.SetOut(&bytes.Buffer{})
	rc.SetErr(&bytes.Buffer{})
	rc.SetArgs([]string{"which", "snooze a thread"})
	_ = rc.Execute()

	if spy.calls() == 0 {
		t.Fatal("expected runAutoRefresh to be invoked via PersistentPreRunE")
	}
}

func TestHook_SubcommandsOfSkipListCommandsSkip(t *testing.T) {
	root := &cobra.Command{Use: "superhuman-pp-cli"}
	authCmd := &cobra.Command{Use: "auth"}
	loginCmd := &cobra.Command{Use: "login"}
	authCmd.AddCommand(loginCmd)
	root.AddCommand(authCmd)
	if !shouldSkipAutoRefresh(loginCmd) {
		t.Fatal("auth login should skip via parent command")
	}
}

